package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvVoluntariaat;
import be.schaubroeck.lpb.rkm.rekenmotor.bv.JaarBedragBvGewoon;
import be.schaubroeck.lpb.rkm.rekenmotor.bv.VerminderingBvPersonenTenLaste;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CheckRegime;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LogTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementChecker;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.FiscaleConstant;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;
import be.schaubroeck.lpb.tools.enumtypes.Fiskgezinstoestand;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.service.FiscaleConstantService;
import com.google.common.collect.Sets;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.Collection;
import java.util.List;
import java.util.Set;

@Slf4j
public abstract class AbstractBerekenBv extends AbstractRekenCommand {

    protected static final LocalDate BASIS_BV_GRENS = new LocalDate(2001, 1, 1);
    private static final Money GRENS_INFINITY = new Money("99999.99");
    private static final LocalDate VERANDERING_JAARBEDRAG_PENSIOEN_DATUM = new LocalDate(2010, 1, 1);
    protected static final LocalDate EINDE_AFRONDEN_NAAR_BENEDEN = new LocalDate(2023, 1, 1);

    protected final ConstantManager constantManager;
    protected final FiscaleConstantService fiscaleConstantService;

    protected FiscaleConstant fiscaleConstanten;
    protected LocalDate taxdatum;

    private boolean voorWeddespiegel = false;

    private final VerminderingBvPersonenTenLaste verminderingBvPersonenTenLaste = new VerminderingBvPersonenTenLaste();
    private final JaarBedragBvGewoon jaarBedragBvGewoon = new JaarBedragBvGewoon();
    protected BvVoluntariaat bvVoluntariaat = null;

    public void setVoorWeddespiegel(boolean voorWeddespiegel) {
        this.voorWeddespiegel = voorWeddespiegel;
    }

    public AbstractBerekenBv(ConstantManager constantManager, NlpGlobalService service) {
        this.fiscaleConstantService = service.getFiscaleConstantService();
        this.constantManager = constantManager;
    }

    public void initFiscaleConstanten(LocalDate taxdatum) {
        this.taxdatum = taxdatum;
        fiscaleConstanten = fiscaleConstantService.getByDate(taxdatum);
    }

    public void initFiscaleConstanten(RekenTijd rekenTijd) {
        if (!rekenTijd.isAchterstal) {
            taxdatum = rekenTijd.eindDatum;
        } else {
            taxdatum = rekenTijd.rekenDatum.dayOfMonth().withMaximumValue();
        }
        log.debug("{} taxDatum:{}", this.getClass().getSimpleName(), this.taxdatum);
        fiscaleConstanten = fiscaleConstantService.getByDate(taxdatum);
        bvVoluntariaat = new BvVoluntariaat(taxdatum);
    }

    public Money berekenBVGewoneBezoldigingBarema(
            Persoon persoon, Money belastbaar, boolean gepensioneerd, boolean isStagairVastbenoemd,
            RekenTijd rekenTijd, RegulManager regulManager) {
        log.debug("{};belastbaar:{}", LogTools.toSimpleLog(persoon), belastbaar);
        PersoonsFiscaliteit persoonsFiscaliteit = RekenTools.getPersoonsFiscaliteitLaatsteGegevens(persoon);
        return berekenBVGewoneBezoldigingBarema(persoonsFiscaliteit, belastbaar, gepensioneerd, isStagairVastbenoemd, rekenTijd, regulManager);
    }

    private static final Set<Fiskgezinstoestand> INKOMEN_PARTNER_GEWOON =
            Sets.immutableEnumSet(Fiskgezinstoestand.ALLEENSTAANDE, Fiskgezinstoestand.EHOOGBPI, Fiskgezinstoestand.ELAAGBPI, Fiskgezinstoestand.EMIDPENS,
                    Fiskgezinstoestand.EHOOGPENS);

    private static final Set<Fiskgezinstoestand> INKOMEN_PARTNER_LAAG =
            Sets.immutableEnumSet(Fiskgezinstoestand.EGEENBPI, Fiskgezinstoestand.ELAAGPENS);

    public Money berekenBVGewoneBezoldigingBarema(
            PersoonsFiscaliteit persoonsFiscaliteit, Money belastbaar, boolean gepensioneerd,
            boolean isStagairVastbenoemd, RekenTijd rekenTijd, RegulManager regulManager) {
        checkRegulContradictieKinderenTenLaste(persoonsFiscaliteit, regulManager);
        Money jaarBedrag = jaarBedragBvGewoon.bereken(belastbaar, rekenTijd);
        Money jaarBedragEega = Money.ZERO;

        log.debug("jaarBedrag:{}", jaarBedrag);
        if (!gepensioneerd) {
            Money bvForfait = bvForfait(jaarBedrag);
            jaarBedrag = jaarBedrag.subtract(bvForfait);
            log.debug("bvForfait:{};jaarBedrag:{}", bvForfait, jaarBedrag);
        }

        Money bedrijfsvoorheffing = Money.ZERO;
        Fiskgezinstoestand fiscaleGezinsToestand = persoonsFiscaliteit.getFiscaleGezinsToestand();
        if (INKOMEN_PARTNER_GEWOON.contains(fiscaleGezinsToestand)) {
            bedrijfsvoorheffing = bedrijfsvoorheffingInkomenPartnerGewoon(jaarBedrag);
        } else if (INKOMEN_PARTNER_LAAG.contains(fiscaleGezinsToestand)) {
            jaarBedragEega = jaarBedrag.multiply(fiscaleConstanten.getJaarBedragPartnerLaagLoonPercentage().movePointLeft(2));
            jaarBedragEega = jaarBedragEega.min(fiscaleConstanten.getJaarBedragPartnerLaagLoonGrens());
            log.debug("jaarBedragEega:{}", jaarBedragEega);
            bedrijfsvoorheffing = bedrijfsvoorheffingInkomenPartnerLaag(jaarBedrag, jaarBedragEega);
        } else {
            regulManager.doRegulException(null, Regulkode.NIET_GEPROGRAMMEERD);
        }

        log.debug("fiscaleGezinsToestand:{};bedrijfsvoorheffing:{}", fiscaleGezinsToestand, bedrijfsvoorheffing);

        Money verminderingBV = verminderingBV(persoonsFiscaliteit, belastbaar, gepensioneerd);
        bedrijfsvoorheffing = bedrijfsvoorheffing.subtract(verminderingBV);
        log.debug("verminderingBV{};bedrijfsvoorheffing:{}", verminderingBV, bedrijfsvoorheffing);

        if (gepensioneerd) {
            Money verminderingBVPensioen = verminderingBvPensioen(jaarBedrag, jaarBedragEega);
            bedrijfsvoorheffing = bedrijfsvoorheffing.subtract(verminderingBVPensioen);
            log.debug("verminderingBVPensioen{};bedrijfsvoorheffing:{}", verminderingBVPensioen, bedrijfsvoorheffing);
        }

        BigDecimal coefficientKrisisTax = constantManager.getActualConstant(Konstanten.KST_BV_KOEFF_KRISISTAX, rekenTijd).getProcentFactor();
        bedrijfsvoorheffing = bedrijfsvoorheffing.multiply(coefficientKrisisTax).round(2);
        bedrijfsvoorheffing = bedrijfsvoorheffing.divide(RekenTools.TWELVE);
        log.debug("bedrijfsvoorheffing/12:{}", bedrijfsvoorheffing);

        if (!gepensioneerd) {
            Money jobKorting = jobKorting(belastbaar);
            bedrijfsvoorheffing = bedrijfsvoorheffing.subtract(jobKorting);
            log.debug("jobKorting{};bedrijfsvoorheffing:{}", jobKorting, bedrijfsvoorheffing);
        }

        Money grensZao1 = fiscaleConstanten.getVerminderingZaoMinMaandGrens();
        Money grensZao2 = fiscaleConstanten.getVerminderingZaoMaxMaandGrens();
        log.debug("grensZao1:{};grensZao2:{};belastbaar:{}", grensZao1, grensZao2, belastbaar);
        if (isStagairVastbenoemd && belastbaar.compareTo(grensZao1) >= 0 && belastbaar.compareTo(grensZao2) <= 0) {
            Money verminderingZao = fiscaleConstanten.getVerminderingZaoMaandBedrag();
            bedrijfsvoorheffing = bedrijfsvoorheffing.subtract(verminderingZao);
            log.debug("Vermindering overheidspersoneel zonder arbeidsovereenkomst{};bedrijfsvoorheffing:{}", verminderingZao, bedrijfsvoorheffing);
        }

        bedrijfsvoorheffing = bedrijfsvoorheffing.max(Money.ZERO);
        if (rekenTijd.beginDatum.isBefore(EINDE_AFRONDEN_NAAR_BENEDEN)) {
            bedrijfsvoorheffing = bedrijfsvoorheffing.round(2, RoundingMode.FLOOR);
        } else {
            bedrijfsvoorheffing = bedrijfsvoorheffing.round(2);
        }
        log.debug("bedrijfsvoorheffing:{}", bedrijfsvoorheffing);
        return bedrijfsvoorheffing;
    }

    protected void checkRegulContradictieKinderenTenLaste(PersoonsFiscaliteit persoonsFiscaliteit, RegulManager regulManager) {
        boolean isOngehuwdWeduweMetKinderenTenLaste = persoonsFiscaliteit.isOngehuwdeWeduweMetKinderenTenLaste();
        int kinderenTenLaste = persoonsFiscaliteit.getTotaalAantalKinderenTenLaste();
        if (kinderenTenLaste == 0 && isOngehuwdWeduweMetKinderenTenLaste) {
            regulManager.doRegulException(null, Regulkode.CONTRADICTIE_KINDEREN_TEN_LASTE);
        }
    }

    private Money bedrijfsvoorheffingInkomenPartnerGewoon(Money jaarBedrag) {
        boolean belastingSchaalOud = taxdatum.compareTo(BASIS_BV_GRENS) < 0;
        Money bedrijfsvoorheffing = basisBV(jaarBedrag, belastingSchaalOud);
        bedrijfsvoorheffing = bedrijfsvoorheffing.round(2);
        if (!belastingSchaalOud) {
            bedrijfsvoorheffing = bedrijfsvoorheffing.subtract(fiscaleConstanten.getVerminderingAlleenstaandeOf2Verdiener());
        }
        return bedrijfsvoorheffing;
    }

    private Money bedrijfsvoorheffingInkomenPartnerLaag(Money jaarBedrag, Money jaarBedragEega) {
        boolean belastingSchaalOud = false;
        Money bedrijfsvoorheffing = basisBV(jaarBedragEega, belastingSchaalOud);
        bedrijfsvoorheffing = bedrijfsvoorheffing.add(basisBV(jaarBedrag.subtract(jaarBedragEega), belastingSchaalOud));
        bedrijfsvoorheffing = bedrijfsvoorheffing.subtract(fiscaleConstanten.getVerminderingJaarBedragPartnerLaagLoon());
        bedrijfsvoorheffing = bedrijfsvoorheffing.round(2);
        return bedrijfsvoorheffing;
    }

    private static final int AANTAL_GRENZEN_FORFAITAIRE_BV = 5;

    private Money bvForfait(Money jaarBedrag) {
        Money forfaitairBedrag = Money.ZERO;
        int aantal = AANTAL_GRENZEN_FORFAITAIRE_BV - 1;
        for (int i = 0; i < aantal; i++) {
            forfaitairBedrag = forfaitairBedrag.add(
                    berekenSchijf(jaarBedrag, fiscaleConstanten.getGrensForfaitaireBV(i), fiscaleConstanten.getGrensForfaitaireBV(i + 1),
                            fiscaleConstanten.getPercentageForfaitaireBV(i + 1)));
        }
        forfaitairBedrag = forfaitairBedrag.add(
                berekenSchijf(jaarBedrag, fiscaleConstanten.getGrensForfaitaireBV(aantal), fiscaleConstanten.getPercentageForfaitaireBV(aantal + 1)));
        return forfaitairBedrag;
    }

    private static final int AANTAL_GRENZEN_BELASTINGSCHAAL_OUD = 7;
    private static final int AANTAL_GRENZEN_BELASTINGSCHAAL = 6;

    private Money basisBV(Money jaarBedrag, boolean belastingOud) {
        int aantalGrenzen = belastingOud ? AANTAL_GRENZEN_BELASTINGSCHAAL_OUD : AANTAL_GRENZEN_BELASTINGSCHAAL;
        List<Money> grenzenBelastingSchaal = fiscaleConstanten.getGrenzenBelastingSchaal(belastingOud);
        List<BigDecimal> percentagesBelastingSchaal = fiscaleConstanten.getPercentagesBelastingSchaal(belastingOud);
        Money bedrijfsvoorheffing = Money.ZERO;
        for (int i = 0; i < aantalGrenzen; i++) {
            bedrijfsvoorheffing = bedrijfsvoorheffing.add(
                    berekenSchijf(jaarBedrag, grenzenBelastingSchaal.get(i), grenzenBelastingSchaal.get(i + 1), percentagesBelastingSchaal.get(i + 1)));
        }
        return bedrijfsvoorheffing;
    }

    private Money verminderingBV(PersoonsFiscaliteit persoonsFiscaliteit, Money maandInkomen, boolean gepensioneerd) {
        Money vermindering = verminderingBvPersonenTenLaste.bereken(fiscaleConstanten, persoonsFiscaliteit);

        if (persoonsFiscaliteit.isMinderValide()) {
            vermindering = vermindering.add(fiscaleConstanten.getVerminderingPersoonInvalide());
        }

        vermindering = vermindering.add(verminderingBvFiscaleGezinsToestand(persoonsFiscaliteit, gepensioneerd));

        if (!voorWeddespiegel && !gepensioneerd && maandInkomen.compareTo(fiscaleConstanten.getVerminderingLaagLoonMaandGrens()) <= 0) {
            vermindering = vermindering.add(fiscaleConstanten.getVerminderingLaagLoonJaarBedrag());
        }
        return vermindering;
    }


    private Money verminderingBvFiscaleGezinsToestand(PersoonsFiscaliteit persoonsFiscaliteit, boolean gepensioneerd) {
        Money vermindering = Money.ZERO;
        Fiskgezinstoestand fiscaleGezinsToestand = persoonsFiscaliteit.getFiscaleGezinsToestand();
        switch (fiscaleGezinsToestand) {
            case ALLEENSTAANDE:
                vermindering = vermindering.add(verminderingBvAlleenstaande(persoonsFiscaliteit, gepensioneerd));
                break;
            case EHOOGBPI:
            case EHOOGPENS:
                break;
            case ELAAGBPI:
                vermindering = vermindering.add(fiscaleConstanten.getVerminderingLaagLoonPartner());
                break;
            case EMIDPENS:
                vermindering = vermindering.add(fiscaleConstanten.getVerminderingPensioenPartner());
                break;
            case EGEENBPI:
            case ELAAGPENS:
                if (persoonsFiscaliteit.isPartnerMinderValide()) {
                    vermindering = vermindering.add(fiscaleConstanten.getVerminderingPartnerInvalide());
                }
                break;
        }
        return vermindering;
    }

    private Money verminderingBvAlleenstaande(PersoonsFiscaliteit persoonsFiscaliteit, boolean gepensioneerd) {
        Money vermindering = Money.ZERO;
        if (!gepensioneerd) {
            vermindering = vermindering.add(fiscaleConstanten.getVerminderingAlleenstaande());
        }
        boolean isOngehuwdWeduweMetKinderenTenLaste = persoonsFiscaliteit.isOngehuwdeWeduweMetKinderenTenLaste();
        int kinderenTenLaste = persoonsFiscaliteit.getTotaalAantalKinderenTenLaste();
        if (kinderenTenLaste > 0 && isOngehuwdWeduweMetKinderenTenLaste) {
            vermindering = vermindering.add(fiscaleConstanten.getVerminderingAlleenstaandeOuder());
        }
        return vermindering;
    }

    private Money verminderingBvPensioen(Money jaarBedrag, Money jaarBedragEega) {
        Money saldoJaarBedrag = jaarBedrag;
        if (taxdatum.compareTo(VERANDERING_JAARBEDRAG_PENSIOEN_DATUM) >= 0 && jaarBedragEega.signum() != 0) {
            saldoJaarBedrag = saldoJaarBedrag.subtract(jaarBedragEega);
        }
        Money grens1 = fiscaleConstanten.getVerminderingPensioenGrens1();
        Money grens2 = fiscaleConstanten.getVerminderingPensioenGrens2();
        BigDecimal koef = fiscaleConstanten.getVerminderingPensioenPercentage();
        Money verminderingPensioen = fiscaleConstanten.getVerminderingPensioenBedrag();

        if (saldoJaarBedrag.compareTo(grens1) > 0 && saldoJaarBedrag.compareTo(grens2) <= 0) {
            Money rv1 = grens2.subtract(saldoJaarBedrag);
            Money rv2 = grens2.subtract(grens1);
            verminderingPensioen = verminderingPensioen.multiply(koef.add(BigDecimal.ONE.subtract(koef).multiply(rv1.divide(rv2))));
        } else if (saldoJaarBedrag.compareTo(grens2) > 0) {
            verminderingPensioen = verminderingPensioen.multiply(koef).round(2);
        }

        return verminderingPensioen;
    }

    private static final int AANTAL_GRENZEN_JOB_KORTING = 22;

    private Money jobKorting(Money belastbaar) {
        Money jobKorting = Money.ZERO;
        for (int grensNr = 0; grensNr < AANTAL_GRENZEN_JOB_KORTING; grensNr++) {
            Money ondergrens = fiscaleConstanten.getGrensJobkorting(grensNr);
            Money bovengrens = fiscaleConstanten.getGrensJobkorting(grensNr + 1);
            if ((belastbaar.compareTo(ondergrens) > 0) && belastbaar.compareTo(bovengrens) <= 0) {
                jobKorting = fiscaleConstanten.getVerminderingJobkorting(grensNr + 1);
                break;
            }
        }
        return jobKorting;
    }

    private Money berekenSchijf(Money basis, Money ondergrens, Money bovengrens, BigDecimal percent) {
        Money schijfWaarde = Money.ZERO;
        if (basis.compareTo(ondergrens) > 0 && (basis.compareTo(bovengrens) <= 0 || (bovengrens.equals(GRENS_INFINITY)) && !ondergrens
                .equals(GRENS_INFINITY))) {
            schijfWaarde = basis.subtract(ondergrens).multiply(percent.movePointLeft(2));
        } else if (basis.compareTo(bovengrens) > 0) {
            schijfWaarde = bovengrens.subtract(ondergrens).multiply(percent.movePointLeft(2));
        }
        schijfWaarde = schijfWaarde.round(2);
        return schijfWaarde;
    }

    //bovengrens infinity
    private Money berekenSchijf(Money basis, Money ondergrens, BigDecimal percent) {
        Money schijfWaarde = Money.ZERO;
        if (basis.compareTo(ondergrens) > 0) {
            schijfWaarde = basis.subtract(ondergrens).multiply(percent.movePointLeft(2));
        }
        schijfWaarde = schijfWaarde.round(2);
        return schijfWaarde;
    }

    protected Money getBelastbaar(RekenBvKey bvKey, RekenBbKey bbKey, Collection<LoonElement> loonElementen) {
        return BvTools.getBelastbaar(bvKey, bbKey, loonElementen, taxdatum);
    }

    protected void herverdeelBedrijfsvoorheffing(
            MoneyKey bvKey, Money bedrijfsvoorheffing, MoneyKey bbKey, Money totaalBelastbaar,
            Collection<LoonElement> loonElementen) {
        LoonElementChecker checkRegime = new CheckRegime(taxdatum, bvKey);
        BedragVerdelerFactory.verdeelBedragVolgensBasisPut(bvKey, bedrijfsvoorheffing, bbKey, totaalBelastbaar, loonElementen, checkRegime);
    }

    protected Money berekenBVAchterstalBarema(Persoon persoon, Money jaarInkomen, Money belastbaar, RekenTijd rekenTijd) {
        PersoonsFiscaliteit persoonsFiscaliteit = RekenTools.getPersoonsFiscaliteitLaatsteGegevens(persoon);
        Money bvAchterstal = Money.ZERO;
        if (persoonsFiscaliteit != null) {
            bvAchterstal = berekenBVAchterstalBarema(persoonsFiscaliteit, jaarInkomen, belastbaar, rekenTijd);
        }
        return bvAchterstal;
    }

    private static final int AANTAL_GRENZEN_ACHTERSTAL_BV = 18;

    public Money berekenBVAchterstalBarema(PersoonsFiscaliteit persoonsFiscaliteit, Money jaarInkomen, Money belastbaar, RekenTijd rekenTijd) {
        int grensNr = 1;
        while (grensNr < AANTAL_GRENZEN_ACHTERSTAL_BV && jaarInkomen.compareTo(fiscaleConstanten.getGrensAchterstalBv(grensNr)) > 0) {
            grensNr++;
        }
        BigDecimal percentage = fiscaleConstanten.getPercentageAchterstalBv(grensNr);
        log.debug("grensNr {}:{}", grensNr - 1, fiscaleConstanten.getGrensAchterstalBv(grensNr - 1));
        if (grensNr < AANTAL_GRENZEN_ACHTERSTAL_BV) {
            log.debug("grensNr {}:{}", grensNr, fiscaleConstanten.getGrensAchterstalBv(grensNr));
        }
        log.debug("percentage {}:{}", grensNr, percentage);

        int kinderenTenLaste = persoonsFiscaliteit.getTotaalAantalKinderenTenLaste();
        int waarvanInvalide = persoonsFiscaliteit.getAantalMinderValideKinderenTenLaste();
        Money grensVrijstelling = fiscaleConstanten.getGrensVerminderingAchterstalKinderenTenLaste(kinderenTenLaste + waarvanInvalide);
        log.debug("kinderenTenLaste:{};waarvanInvalide:{};grensVrijstelling:{}", kinderenTenLaste, waarvanInvalide, grensVrijstelling);
        if (jaarInkomen.compareTo(grensVrijstelling) < 0) {
            belastbaar = belastbaar.subtract(grensVrijstelling.subtract(jaarInkomen));
            log.debug("belastbaar:{}", belastbaar);
        }

        Money bedrijfsVoorheffing = belastbaar.multiply(percentage.movePointLeft(2));
        BigDecimal coefficientKrisisTax = constantManager.getActualConstant(Konstanten.KST_BV_KOEFF_KRISISTAX, rekenTijd).getProcentFactor();
        bedrijfsVoorheffing = bedrijfsVoorheffing.multiply(coefficientKrisisTax).round(2);
        bedrijfsVoorheffing = bedrijfsVoorheffing.max(Money.ZERO);

        return bedrijfsVoorheffing;
    }

    private static final int AANTAL_GRENZEN_TOEVALLIGE_VERGOEDINGEN = 3;

    protected Money berekenToevalligeVergoedingenBarema(Money belastbaar, RekenTijd rekenTijd) {
        int grensNr = 1;
        while (grensNr < AANTAL_GRENZEN_TOEVALLIGE_VERGOEDINGEN
                && belastbaar.compareTo(fiscaleConstanten.getGrensToevalligeVergoedingen(grensNr)) > 0) {
            grensNr++;
        }
        log.debug("grensNr {}:{}", grensNr - 1, fiscaleConstanten.getGrensToevalligeVergoedingen(grensNr - 1));
        if (grensNr < AANTAL_GRENZEN_TOEVALLIGE_VERGOEDINGEN) {
            log.debug("grensNr {}:{}", grensNr, fiscaleConstanten.getGrensToevalligeVergoedingen(grensNr));
        }
        BigDecimal percentage = fiscaleConstanten.getPercentageToevalligeVergoedingen(grensNr);
        log.debug("percentage:{}", percentage);

        Money bedrijfsvoorheffing = belastbaar.multiply(percentage);
        BigDecimal coefficientKrisisTax = constantManager.getActualConstant(Konstanten.KST_BV_KOEFF_KRISISTAX, rekenTijd).getProcentFactor();
        bedrijfsvoorheffing = bedrijfsvoorheffing.multiply(coefficientKrisisTax).round(2);
        bedrijfsvoorheffing = bedrijfsvoorheffing.max(Money.ZERO);
        return bedrijfsvoorheffing;
    }
}
